VALUES
  ('islands-e0adf6cd-moex-00049', 'islands-e0adf6cd', 'islands-e0adf6cd-moex-114-3082b5f1', 'sub-islands-e0adf6cd-05', NULL, 'single_choice', '下列何者非屬地方制度法所稱之委辦事項？ 內政部將有關外國人入出國、停留、居留、永久居留、收容管理及驅逐出國等業務，委由各直 轄市、縣（市）政府辦理 宜蘭縣政府將核發土地使用分區證明書之權限，委由其轄區內鄉鎮市公所辦理 臺北市政府將部分涉及捷運管理之業務交由新北市政府辦理 內政部將土地徵收補償費、遷移費的查估委由各直轄市或縣（市）政府辦理', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:56+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "504", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "教育行政"}'::jsonb, NULL),
  ('islands-e0adf6cd-moex-00050', 'islands-e0adf6cd', 'islands-e0adf6cd-moex-114-3082b5f1', 'sub-islands-e0adf6cd-05', NULL, 'single_choice', '法律規定「本法所稱主管機關：在中央為內政部」，下列敘述何者錯誤？ 該法條可作為定管轄競合之依據 該法條不得作為行政機關限制人民基本權利之依據 該法條為事務管轄之依據 該法條屬於組織法規定', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:56+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "504", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "教育行政"}'::jsonb, NULL),
  ('islands-e0adf6cd-moex-00051', 'islands-e0adf6cd', 'islands-e0adf6cd-moex-114-3082b5f1', 'sub-islands-e0adf6cd-05', NULL, 'single_choice', '依公務員懲戒法規定，下列敘述何者正確？ 受降級處分者，自改敘之日起，4年內不得晉敘、陞任或遷調主管職務 申誡處分，得以口頭方式為之，受申誡人請求，方須作成書面 罰款之懲戒處分不得與剝奪、減少退休（職、伍）金之懲戒處分併為處分 剝奪、減少退休（職、伍）金之懲戒處分，得對現任公務員將來之退休（職、伍）金扣減之', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:56+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "504", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "教育行政"}'::jsonb, NULL),
  ('islands-e0adf6cd-moex-00052', 'islands-e0adf6cd', 'islands-e0adf6cd-moex-114-3082b5f1', 'sub-islands-e0adf6cd-05', NULL, 'single_choice', '甲任職於某縣政府教育處體育保健科之薦任6職等科員，經同縣府農業處借調到自然生態保育科 擔任薦任6職等科員並占其職缺，甲不服其借調，應依下列何種管道尋求救濟？ 申訴、再申訴程序  訴願程序  復審程序  復查程序', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:56+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "504", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "教育行政"}'::jsonb, NULL),
  ('islands-e0adf6cd-moex-00053', 'islands-e0adf6cd', 'islands-e0adf6cd-moex-114-3082b5f1', 'sub-islands-e0adf6cd-05', NULL, 'single_choice', '有關公務人員權利義務之敘述，下列何者錯誤？ 甲為公立學校校長，有公務員服務法之適用 乙為縣長之機要秘書，亦受公務人員任用法之保障，縣長對其機要職務不可隨時將其免職 丙公務人員在職死亡者，其遺族丁可向丙之服務機關申辦撫卹 戊為現職軍人，不得參加公務人員協會', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:56+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "504", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "教育行政"}'::jsonb, NULL),
  ('islands-e0adf6cd-moex-00054', 'islands-e0adf6cd', 'islands-e0adf6cd-moex-114-3082b5f1', 'sub-islands-e0adf6cd-05', NULL, 'single_choice', '衛生福利部就違反食品安全衛生管理法事件之裁罰，訂定「食品安全衛生管理法第四十七條第八 款及第十款標示違規罰鍰處理原則」，此處理原則性質屬於下列何者？ 一般處分  法規命令  行政規則  行政指導 30840、31140 31940 50430', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:56+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "504", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "教育行政"}'::jsonb, NULL),
  ('islands-e0adf6cd-moex-00055', 'islands-e0adf6cd', 'islands-e0adf6cd-moex-114-3082b5f1', 'sub-islands-e0adf6cd-05', NULL, 'single_choice', '下列何者非屬對物的一般處分？ 管理機關公告封閉危橋，不再提供人車通行 市政府將某大樓啟用為市府某局處辦公室 主管機關將海軍管理之眷村指定為文化景觀 交通路口所設紅綠燈號誌之指揮交通', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:56+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "504", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "教育行政"}'::jsonb, NULL),
  ('islands-e0adf6cd-moex-00056', 'islands-e0adf6cd', 'islands-e0adf6cd-moex-114-3082b5f1', 'sub-islands-e0adf6cd-05', NULL, 'single_choice', '甲向乙戶政事務所申請改名遭拒，下列敘述何者錯誤？ 乙拒絕甲改名之行為性質為行政處分 甲不服乙拒絕更名得依法循序提訴願、行政訴訟 甲提起爭訟中，乙同意甲改名並為登記，且通知財稅機關改名之事實，該通知性質為行政處分 財稅機關依乙通知，將甲所有稅籍姓名變更並通知甲，該通知甲稅籍變更之行為，為行政處分', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:56+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "504", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "教育行政"}'::jsonb, NULL),
  ('islands-e0adf6cd-moex-00057', 'islands-e0adf6cd', 'islands-e0adf6cd-moex-114-3082b5f1', 'sub-islands-e0adf6cd-05', NULL, 'single_choice', '依行政程序法規定，關於行政處分之補正，下列敘述何者正確？ 經聽證之行政處分，僅得於向行政法院起訴前補正 必須記明之附款，得因事後記明而補正 處分機關告知之救濟期間有錯誤時，應由該機關以通知補正之，並自通知送達之翌日起算法定 期間 應以證書方式作成而未給予證書，得因事後補發而補正', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:56+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "504", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "教育行政"}'::jsonb, NULL),
  ('islands-e0adf6cd-moex-00058', 'islands-e0adf6cd', 'islands-e0adf6cd-moex-114-3082b5f1', 'sub-islands-e0adf6cd-05', NULL, 'single_choice', '衛生福利部中央健康保險署與保險醫事服務機構可以簽訂全民健保契約，中央健康保險署得就醫 事服務機構申請同意為特約醫事服務機構之資格、程序、審查基準訂定法規命令，依實務見解， 關於該法規命令之敘述，下列何者正確？ 授權是否具體明確，僅以該授權法律之文義為準 法規命令之規範內容，衛生福利部享有判斷餘地 屬於相對法律保留範圍 衛生福利部得選擇訂定行政規則替代該法規命令', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:56+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "504", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "教育行政"}'::jsonb, NULL)
